const Card = ({ 
  children, 
  padding = 'md', 
  className = '',
  role = 'article',
  ariaLabel
}) => {
  const paddingMap = {
    sm: 'p-[var(--component-card-padding-sm)]',
    md: 'p-[var(--component-card-padding-md)]',
    lg: 'p-[var(--component-card-padding-lg)]'
  };

  const baseStyles = `
    rounded-[var(--component-card-radius)]
    bg-[var(--component-card-bg)]
    border border-[var(--component-card-border)]
    shadow-[var(--component-card-shadow)]
    transition-shadow duration-200 ease-in-out
  `;

  const hoverStyles = `
    hover:shadow-lg
  `;

  const combinedClasses = `
    ${baseStyles}
    ${hoverStyles}
    ${paddingMap[padding]}
    ${className}
  `.trim().split('\n').map(s => s.trim()).filter(Boolean).join(' ');

  return (
    <div
      role={role}
      aria-label={ariaLabel}
      className={combinedClasses}
    >
      {children}
    </div>
  );
};

